import{_ as e,o as a,c as d,ag as r}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Data Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"theory/databases/data-concepts.md","filePath":"theory/databases/data-concepts.md"}'),o={name:"theory/databases/data-concepts.md"};function s(n,t,i,l,c,h){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="data-concepts" tabindex="-1">Data Concepts <a class="header-anchor" href="#data-concepts" aria-label="Permalink to &quot;Data Concepts&quot;">​</a></h1><p>Before a database can be designed, we need to understand what data actually is — and why &quot;data&quot; and &quot;information&quot; are not the same thing. The quality of data determines the quality of every decision made from it.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10–11</p><p>Data vs information vs knowledge is introduced in Grade 10. Data quality characteristics and data types are extended in Grade 11.</p></div><hr><h2 id="data-vs-information-vs-knowledge" tabindex="-1">Data vs Information vs Knowledge <a class="header-anchor" href="#data-vs-information-vs-knowledge" aria-label="Permalink to &quot;Data vs Information vs Knowledge&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>Definition</th><th>Example</th></tr></thead><tbody><tr><td><strong>Data</strong></td><td>Raw, unprocessed facts — no context or meaning</td><td><code>85</code>, <code>2024-03-15</code>, <code>Ayden</code></td></tr><tr><td><strong>Information</strong></td><td>Data that has been processed, organised, and given context</td><td>&quot;Ayden scored 85% on the March 2024 test&quot;</td></tr><tr><td><strong>Knowledge</strong></td><td>Information applied with understanding and experience</td><td>&quot;Ayden is performing well and likely to pass; a 90%+ target is achievable&quot;</td></tr></tbody></table><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Data → [Process] → Information → [Apply experience] → Knowledge</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Why the difference matters:</strong></p><ul><li>A database stores <strong>data</strong></li><li>Reports and dashboards present <strong>information</strong></li><li>Decisions require <strong>knowledge</strong></li></ul><hr><h2 id="characteristics-of-quality-data" tabindex="-1">Characteristics of Quality Data <a class="header-anchor" href="#characteristics-of-quality-data" aria-label="Permalink to &quot;Characteristics of Quality Data&quot;">​</a></h2><p>For data to be useful, it must be:</p><table tabindex="0"><thead><tr><th>Characteristic</th><th>Meaning</th><th>Bad Example</th><th>Good Example</th></tr></thead><tbody><tr><td><strong>Accurate</strong></td><td>Correct and error-free</td><td>Date of birth: 30 Feb</td><td>Date of birth: 28 Feb</td></tr><tr><td><strong>Complete</strong></td><td>All required fields filled</td><td>Missing phone number</td><td>All contact details present</td></tr><tr><td><strong>Consistent</strong></td><td>Same format throughout</td><td>&quot;012 555 1234&quot; / &quot;0125551234&quot; mixed</td><td>All numbers formatted the same</td></tr><tr><td><strong>Relevant</strong></td><td>Appropriate for the purpose</td><td>Storing shoe size in a school database</td><td>Only collecting educationally relevant data</td></tr><tr><td><strong>Timely</strong></td><td>Up to date</td><td>Using a 5-year-old address</td><td>Updated address at last visit</td></tr><tr><td><strong>Valid</strong></td><td>Within acceptable range/format</td><td>Mark: 150</td><td>Mark: 85</td></tr><tr><td><strong>Unique</strong></td><td>No duplicate records</td><td>Same student entered twice</td><td>Each student appears once</td></tr></tbody></table><hr><h2 id="data-types" tabindex="-1">Data Types <a class="header-anchor" href="#data-types" aria-label="Permalink to &quot;Data Types&quot;">​</a></h2><p>Every field in a database stores a specific type of data:</p><table tabindex="0"><thead><tr><th>Data Type</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Text / String</strong></td><td>Characters — letters, numbers, symbols</td><td>Name, email address, suburb</td></tr><tr><td><strong>Integer</strong></td><td>Whole numbers</td><td>Age, quantity, grade level</td></tr><tr><td><strong>Real / Float</strong></td><td>Numbers with decimals</td><td>Mark as percentage, price</td></tr><tr><td><strong>Boolean</strong></td><td>True/False only</td><td>Paid: Yes/No, Active: True/False</td></tr><tr><td><strong>Date</strong></td><td>Calendar date</td><td>Date of birth: 2008-05-15</td></tr><tr><td><strong>Time</strong></td><td>Time of day</td><td>Arrival time: 08:30</td></tr><tr><td><strong>Date/Time</strong></td><td>Combined date and time</td><td>Transaction: 2024-03-15 14:32:05</td></tr><tr><td><strong>Currency</strong></td><td>Monetary value (formatted)</td><td>Price: R299.99</td></tr><tr><td><strong>Auto-number</strong></td><td>Automatically incremented integer</td><td>StudentID: 1001, 1002, 1003...</td></tr><tr><td><strong>OLE Object / BLOB</strong></td><td>Binary large objects (images, files)</td><td>Student photo</td></tr><tr><td><strong>Memo / Long Text</strong></td><td>Long text fields</td><td>Notes, descriptions</td></tr></tbody></table><hr><h2 id="sources-of-data" tabindex="-1">Sources of Data <a class="header-anchor" href="#sources-of-data" aria-label="Permalink to &quot;Sources of Data&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Surveys / forms</strong></td><td>Questionnaires, registration forms</td></tr><tr><td><strong>Transactions</strong></td><td>Purchase records, bank statements</td></tr><tr><td><strong>Sensors / IoT</strong></td><td>Temperature readings, GPS data</td></tr><tr><td><strong>Web activity</strong></td><td>Clicks, page views, searches</td></tr><tr><td><strong>Social media</strong></td><td>Posts, comments, likes</td></tr><tr><td><strong>Public records</strong></td><td>Census data, government databases</td></tr></tbody></table><hr><h2 id="data-collection-methods" tabindex="-1">Data Collection Methods <a class="header-anchor" href="#data-collection-methods" aria-label="Permalink to &quot;Data Collection Methods&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Description</th><th>Advantages</th><th>Disadvantages</th></tr></thead><tbody><tr><td><strong>Online forms</strong></td><td>Web-based input</td><td>Wide reach, automatic validation</td><td>Requires internet access</td></tr><tr><td><strong>Paper forms</strong></td><td>Physical forms</td><td>No technology required</td><td>Must be manually captured</td></tr><tr><td><strong>Barcode/QR scanning</strong></td><td>Automated reading</td><td>Fast, accurate</td><td>Requires equipment</td></tr><tr><td><strong>RFID</strong></td><td>Radio frequency identification</td><td>Passive (no action needed)</td><td>Cost of tags and readers</td></tr><tr><td><strong>Biometrics</strong></td><td>Fingerprint, face recognition</td><td>Unique, hard to fake</td><td>Privacy concerns, cost</td></tr><tr><td><strong>API / data feeds</strong></td><td>Automated transfer from other systems</td><td>Real-time, no manual entry</td><td>Technical setup required</td></tr></tbody></table><hr><h2 id="data-storage" tabindex="-1">Data Storage <a class="header-anchor" href="#data-storage" aria-label="Permalink to &quot;Data Storage&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Storage Method</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Flat file</strong></td><td>Simple text/CSV — one table, no relationships</td><td>Spreadsheet, CSV export</td></tr><tr><td><strong>Relational database</strong></td><td>Multiple related tables with keys</td><td>MS Access, MySQL, PostgreSQL</td></tr><tr><td><strong>NoSQL database</strong></td><td>Non-tabular storage — documents, graphs</td><td>MongoDB, Firebase</td></tr><tr><td><strong>Data warehouse</strong></td><td>Large-scale analytics storage</td><td>For business intelligence</td></tr><tr><td><strong>Cloud database</strong></td><td>Database hosted in cloud</td><td>AWS RDS, Google Cloud SQL</td></tr></tbody></table><hr><h2 id="file-types-and-data-storage" tabindex="-1">File Types and Data Storage <a class="header-anchor" href="#file-types-and-data-storage" aria-label="Permalink to &quot;File Types and Data Storage&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Use</th><th>Can store relationships?</th></tr></thead><tbody><tr><td><code>.csv</code></td><td>Comma-separated values — simple tabular data</td><td>No</td></tr><tr><td><code>.xlsx</code></td><td>Excel spreadsheet</td><td>No (without complex workarounds)</td></tr><tr><td><code>.accdb</code></td><td>Microsoft Access database</td><td>Yes</td></tr><tr><td><code>.sql</code></td><td>SQL database dump</td><td>Yes</td></tr><tr><td><code>.json</code></td><td>Data exchange format</td><td>Partial (nested structures)</td></tr><tr><td><code>.xml</code></td><td>Data exchange format</td><td>Partial</td></tr><tr><td><code>.db</code></td><td>SQLite database</td><td>Yes</td></tr></tbody></table><hr><h2 id="data-lifecycle" tabindex="-1">Data Lifecycle <a class="header-anchor" href="#data-lifecycle" aria-label="Permalink to &quot;Data Lifecycle&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Collection → Storage → Processing → Analysis → Distribution → Archiving/Deletion</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><table tabindex="0"><thead><tr><th>Stage</th><th>What happens</th></tr></thead><tbody><tr><td><strong>Collection</strong></td><td>Data gathered from various sources</td></tr><tr><td><strong>Storage</strong></td><td>Saved in a database or file system</td></tr><tr><td><strong>Processing</strong></td><td>Cleaned, validated, transformed</td></tr><tr><td><strong>Analysis</strong></td><td>Queries, reports, and summaries produced</td></tr><tr><td><strong>Distribution</strong></td><td>Information shared with users who need it</td></tr><tr><td><strong>Archiving</strong></td><td>Old data stored long-term</td></tr><tr><td><strong>Deletion</strong></td><td>Data that is no longer needed is securely removed</td></tr></tbody></table><hr><h2 id="metadata" tabindex="-1">Metadata <a class="header-anchor" href="#metadata" aria-label="Permalink to &quot;Metadata&quot;">​</a></h2><p><strong>Metadata</strong> is data about data — it describes the properties of other data.</p><table tabindex="0"><thead><tr><th>Example</th><th>Metadata</th></tr></thead><tbody><tr><td>A photo</td><td>Date taken, camera settings, GPS location, file size</td></tr><tr><td>An email</td><td>Sender, recipient, timestamp, subject</td></tr><tr><td>A document</td><td>Author, creation date, file size, word count</td></tr><tr><td>A database record</td><td>Last modified, created by which user</td></tr></tbody></table><hr><h2 id="primary-vs-secondary-data" tabindex="-1">Primary vs Secondary Data <a class="header-anchor" href="#primary-vs-secondary-data" aria-label="Permalink to &quot;Primary vs Secondary Data&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Primary Data</th><th>Secondary Data</th></tr></thead><tbody><tr><td>Source</td><td>Collected firsthand for this purpose</td><td>Collected previously for another purpose</td></tr><tr><td>Relevance</td><td>Highly relevant to your needs</td><td>May not perfectly fit your needs</td></tr><tr><td>Cost</td><td>Expensive (time, resources)</td><td>Cheap (already exists)</td></tr><tr><td>Currency</td><td>Fresh and current</td><td>May be outdated</td></tr><tr><td>Examples</td><td>Survey you conduct</td><td>Government census, published studies</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Data</strong></td><td>Raw, unprocessed facts</td></tr><tr><td><strong>Information</strong></td><td>Processed data that has meaning and context</td></tr><tr><td><strong>Knowledge</strong></td><td>Information applied with experience and understanding</td></tr><tr><td><strong>Data type</strong></td><td>Category of value a field can store (Integer, String, etc.)</td></tr><tr><td><strong>Metadata</strong></td><td>Data describing properties of other data</td></tr><tr><td><strong>Flat file</strong></td><td>Single-table data storage (e.g. CSV)</td></tr><tr><td><strong>Relational database</strong></td><td>Multiple related tables linked by keys</td></tr><tr><td><strong>Data quality</strong></td><td>How accurate, complete, consistent, and valid data is</td></tr><tr><td><strong>Primary data</strong></td><td>Data collected firsthand for a specific purpose</td></tr><tr><td><strong>Secondary data</strong></td><td>Data collected previously for another purpose</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is the difference between data and information?&quot;</strong> — Data is raw unprocessed facts (e.g. &quot;85&quot;); information is data that has been processed and given context (e.g. &quot;Ayden scored 85% in the March test&quot;)</p></li><li><p><strong>&quot;Give FOUR characteristics of quality data&quot;</strong> — accurate, complete, consistent, relevant, timely, valid, unique</p></li><li><p><strong>&quot;Name THREE data types used in a database&quot;</strong> — Text/String, Integer, Real/Float, Boolean, Date, Currency, Auto-number</p></li><li><p><strong>&quot;What is metadata? Give ONE example.&quot;</strong> — Data that describes other data; example: a photo&#39;s metadata includes the date taken, GPS location, and camera settings</p></li><li><p><strong>&quot;Explain the difference between primary and secondary data&quot;</strong> — Primary: collected firsthand for the specific purpose (your survey); Secondary: collected previously for a different purpose (government census)</p></li></ol></div>',46)])])}const p=e(o,[["render",s]]);export{u as __pageData,p as default};
